import{_ as a,o as l,c as t,a0 as r}from"./chunks/framework.jwovEGr5.js";const u=JSON.parse('{"title":"Alliance Leader Guide","description":"","frontmatter":{},"headers":[],"relativePath":"roles/alliance-leader.md","filePath":"roles/alliance-leader.md"}'),i={name:"roles/alliance-leader.md"};function o(n,e,s,h,d,c){return l(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="alliance-leader-guide" tabindex="-1">Alliance Leader Guide <a class="header-anchor" href="#alliance-leader-guide" aria-label="Permalink to &quot;Alliance Leader Guide&quot;">​</a></h1><p>This is the <strong>start here</strong> guide for <code>Alliance Leader</code> users. It focuses on your real home base, your premium choices, and the guides you will use most often.</p><h2 id="your-management-home-my-alliance" tabindex="-1">Your management home: My Alliance <a class="header-anchor" href="#your-management-home-my-alliance" aria-label="Permalink to &quot;Your management home: My Alliance&quot;">​</a></h2><p>For an Alliance Leader, <strong>My Alliance</strong> is the main home page.</p><p>Start here:</p><ul><li><a href="./../how-to/my-alliance.html">Use the My Alliance Page</a></li></ul><p>That page is where you review your alliance summary, usage, premium offers, and quick paths into players, analytics, imports, and reports.</p><h2 id="what-you-run-day-to-day" tabindex="-1">What you run day to day <a class="header-anchor" href="#what-you-run-day-to-day" aria-label="Permalink to &quot;What you run day to day&quot;">​</a></h2><p>Alliance Leaders usually spend most of their time in these guides:</p><ul><li><a href="./../how-to/players-directory.html">Players Directory</a></li><li><a href="./../how-to/add-player.html">Add a Player</a></li><li><a href="./../how-to/edit-player.html">Edit Player Details</a></li><li><a href="./../how-to/player-profile.html">Read a Player Profile</a></li><li><a href="./../events/templates-overview.html">Event Templates &amp; Instances Explained</a></li><li><a href="./../how-to/create-instance.html">Create an Event Instance</a></li><li><a href="./../imports/overview.html">How Screenshot Imports Work</a></li><li><a href="./../how-to/manual-input.html">Enter Results Manually</a></li><li><a href="./../analytics/overview.html">Analytics Overview</a></li><li><a href="./../how-to/rewards.html">Review Reward Eligibility</a></li></ul><h2 id="premium-offers-and-grants" tabindex="-1">Premium offers and grants <a class="header-anchor" href="#premium-offers-and-grants" aria-label="Permalink to &quot;Premium offers and grants&quot;">​</a></h2><p>Alliance Leaders are the main role for handling alliance-side premium offers.</p><p>Read these together:</p><ul><li><a href="./../subscriptions/accept-grant.html">Accept a Premium Offer</a></li><li><a href="./../subscriptions/effective-plan.html">Which Plan Applies to My Alliance?</a></li><li><a href="./../subscriptions/premium-features.html">Premium Features</a></li></ul><p>You may need to:</p><ul><li>accept a kingdom premium offer</li><li>reject an offer</li><li>give back an accepted grant later</li></ul><h2 id="the-kingdom-analytics-rule" tabindex="-1">The kingdom analytics rule <a class="header-anchor" href="#the-kingdom-analytics-rule" aria-label="Permalink to &quot;The kingdom analytics rule&quot;">​</a></h2><p>Being inside a kingdom does <strong>not</strong> automatically let you open the Kingdom analytics tab.</p><p>That tab appears for alliance-scoped leaders only when:</p><ul><li>your alliance has an <strong>accepted</strong> kingdom grant, and</li><li>that grant includes the <code>kingdom_analytics_for_granted_alliances</code> feature</li></ul><p>See <a href="./../analytics/kingdom.html">Kingdom Analytics</a> and <a href="./../subscriptions/accept-grant.html">Accept a Premium Offer</a>.</p><h2 id="what-you-cannot-do" tabindex="-1">What you cannot do <a class="header-anchor" href="#what-you-cannot-do" aria-label="Permalink to &quot;What you cannot do&quot;">​</a></h2><p>Alliance Leaders cannot:</p><ul><li>manage users or role assignments</li><li>create or delete alliances</li><li>purge the recycle bin</li><li>use the Supreme Admin subscription tools</li></ul><p>If you hit an access refusal, check <a href="./../getting-started/access-denied.html">&quot;You don&#39;t have access&quot;</a>.</p><h2 id="good-pages-to-keep-bookmarked" tabindex="-1">Good pages to keep bookmarked <a class="header-anchor" href="#good-pages-to-keep-bookmarked" aria-label="Permalink to &quot;Good pages to keep bookmarked&quot;">​</a></h2><ul><li><a href="./../how-to/recycle-bin.html">Use the Recycle Bin</a></li><li><a href="./../how-to/restore-requests.html">Request &amp; Approve Restores</a></li><li><a href="./../how-to/reports.html">File &amp; Track Reports</a></li><li><a href="./../subscriptions/suspension.html">Suspension &amp; Limited Mode</a></li></ul>',27)])])}const p=a(i,[["render",o]]);export{u as __pageData,p as default};
